use fastly::http::{Method, StatusCode};
use fastly::{Error, Request, Response};
use fastly::backend::Backend;
use fastly::http::header::{HOST, FORWARDED};

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    // Define backend configurations
    let backend_a = Backend::builder("backend_a")
        .host("backend-a.example.com")
        .port(443)
        .use_ssl(true)
        .ssl_sni_hostname("backend-a.example.com")
        .build()?;

    let backend_b = Backend::builder("backend_b")
        .host("backend-b.example.com")
        .port(443)
        .use_ssl(true)
        .ssl_sni_hostname("backend-b.example.com")
        .build()?;

    // Determine which backend to route to based on the request path
    let backend = match req.get_path() {
        "/service-a" => backend_a,
        "/service-b" => backend_b,
        _ => return Ok(Response::from_status(StatusCode::NOT_FOUND)),
    };

    // Remove sensitive headers before forwarding
    req.remove_header(HOST);
    req.remove_header(FORWARDED);

    // Forward the request to the selected backend
    let mut beresp = req.send(backend)?;

    // Handle response from backend
    if beresp.get_status().is_success() {
        Ok(beresp)
    } else {
        Ok(Response::from_status(StatusCode::BAD_GATEWAY))
    }
}